const PIECES_A = [{"id": "mobile-security", "name": "Mobile Phones & Security", "short": "Mobile Security", "icon": "📱", "color": "#4FA6D9", "blurb": "Are they on the right mobile phones and contract for their business — and is anyone protecting those devices?", "criteria": ["On a different mobile provider, unhappy or unsure of their contract end date — a clean switch opportunity", "A phone contract or handset upgrade coming up with no plan to add protection alongside it", "A lot of phones or laptops with nobody managing or protecting them (no MDM or MTD)"], "implicationQuestions": {"result_mid_byod_small": "Even with just a few, what's on those specific phones that would worry you if one went missing?", "result_hot_byod_mid": "With that many personal devices across different platforms, what's the realistic worst case if one of them got compromised?", "result_hot_byod_large": "With most of the business on personal devices, what would a single compromised phone actually expose across the business?", "result_mid_unmanaged_small": "Even though it's small and consistent, what would it take for someone to notice if one went missing tonight?", "result_hot_unmanaged_mid": "With a fleet that size and no visibility, how would you even know if one of them was already compromised?", "result_hot_unmanaged_large": "At that scale with zero management, what would a single serious incident across the fleet actually cost you?", "result_none_managed_full": "Good — if the business doubled in size next year, would this setup still hold up as easily?", "result_dev_managed_gaps": "For whatever's in those gaps, what's the actual risk of leaving them unmanaged versus closing them now?", "result_hot_managed_shadow": "For the devices sitting outside management, what happens if one of them is the one that gets compromised?", "result_dev_mixed_mostly_managed": "For that small BYOD tail, what do those specific people typically access that the rest of the company doesn't?", "result_hot_mixed_even": "With no consistency on either side, which half worries you more — and why?", "result_hot_mixed_mostly_byod": "If the wider team has just as much access as leadership, what does that imply about where the real risk actually sits?", "result_dev_rugged_small": "As that fleet grows, what would it take to keep the same consistency you have today?", "result_hot_rugged_separate": "With those devices managed separately, what happens if the person who manages them informally is out sick or leaves?", "result_hot_rugged_unknown": "If one of those field devices went missing tomorrow, would anyone even know what was on it?", "result_warm_unknown": "If it turned out there were more devices out there than you thought, how big a surprise would that be?", "result_mid_unknown": "What's the quickest way we could get a rough headcount without it being a big exercise?", "result_none_unknown": "Is there anything — a device refresh, a new hire process — that would make this worth revisiting?", "result_hot_contract": "If one of those new phones went missing or got compromised with nothing managing it, what would that actually mean for you — lost data, a compliance headache, or both?", "result_mid_contract": "What's stopped you looking into it before now — time, cost, or just not knowing where to start?", "result_none_contract": "Fair enough — when did you last actually confirm that coverage extends to laptops and desktops as well as phones?", "result_hot_incumbent": "If a bad experience with them happened again, what would that actually cost you — downtime, hassle, or just frustration?", "result_mid_incumbent": "What would make it worth the hassle of actually comparing your options?", "result_none_incumbent": "Fair enough — what would it take for that to change, even at renewal time?"}, "needPayoff": {"byod_probe": "If every one of those personal devices could be enrolled and protected without staff feeling like Big Brother, would that be worth doing?", "unmanaged_probe": "If that whole fleet sat under one management platform with full visibility, would that solve it?", "managed_probe": "If every device — no exceptions — sat under the same management policy, would that close the picture completely?", "mixed_probe": "If BYOD and company-issued devices both sat under the exact same security policy, would that remove the inconsistency?", "rugged_probe": "If field and rugged devices were brought into the same management platform as everyone else, would that close the blind spot?", "unknown_probe": "If we ran a quick, no-obligation count of what's actually out there, would that be useful regardless of what it finds?", "contract_probe": "If we timed the phone upgrade together with proper device management and threat protection — and used the same visit to check whether your laptops and desktops have similar protection — would that be worth doing as one project rather than separately?", "incumbent_probe": "If we could match or beat what you're paying today, with phones and a contract that just work, would it be worth a quick comparison before your renewal?"}, "tree": {"start": {"type": "situation", "q": "How are staff mobiles handled — whose devices are they, and is there any management or security on them?", "options": [{"label": "We're actually with a different mobile phone provider", "next": "incumbent_probe"}, {"label": "Staff use their own phones for work — no company management at all", "next": "byod_probe"}, {"label": "We have company-owned phones, but no real management or security on them", "next": "unmanaged_probe"}, {"label": "We have company phones with some kind of MDM or management already", "next": "managed_probe"}, {"label": "It's a real mix — some BYOD, some company-issued, no consistency", "next": "mixed_probe"}, {"label": "We've got field, warehouse or rugged devices for specific roles", "next": "rugged_probe"}, {"label": "Honestly, mobiles aren't really something I think about", "next": "unknown_probe"}, {"label": "Our mobile contract is due for renewal, or the phones are due an upgrade", "next": "contract_probe"}]}, "byod_probe": {"type": "problem", "q": "Roughly how many staff are we talking, and is it mostly one device type or a real mix of iPhone and Android?", "options": [{"label": "Just a handful, fairly similar devices", "next": "result_mid_byod_small"}, {"label": "A good number — 10 to 50 or so, mixed device types", "next": "result_hot_byod_mid"}, {"label": "Most of the business, right across iPhone, Android and everything in between", "next": "result_hot_byod_large"}]}, "unmanaged_probe": {"type": "problem", "q": "How many company phones are we talking, and what's the mix — mostly one make, or several different types issued over time?", "options": [{"label": "A small number, fairly consistent", "next": "result_mid_unmanaged_small"}, {"label": "A decent fleet, a mix of models bought at different times", "next": "result_hot_unmanaged_mid"}, {"label": "A large fleet across multiple device types", "next": "result_hot_unmanaged_large"}]}, "managed_probe": {"type": "problem", "q": "How many devices are enrolled, and does the management cover every device, or just some of the fleet?", "options": [{"label": "All of them, small fleet, fully enrolled", "next": "result_none_managed_full"}, {"label": "Most of them, a few gaps here and there", "next": "result_dev_managed_gaps"}, {"label": "Only some — a fair few devices are outside management entirely", "next": "result_hot_managed_shadow"}]}, "mixed_probe": {"type": "problem", "q": "Roughly what proportion is BYOD versus company-issued, and is there any consistency in how either group is secured?", "options": [{"label": "Mostly company-issued with a few personal phones here and there", "next": "result_dev_mixed_mostly_managed"}, {"label": "Close to 50/50, and neither side is really secured consistently", "next": "result_hot_mixed_even"}, {"label": "Mostly BYOD with company phones for a few senior people only", "next": "result_hot_mixed_mostly_byod"}]}, "rugged_probe": {"type": "problem", "q": "How many of those field or rugged devices are out there, and are they managed the same way as regular staff phones, or handled separately?", "options": [{"label": "Small number, handled the same as everyone else", "next": "result_dev_rugged_small"}, {"label": "A meaningful number, but managed completely separately or informally", "next": "result_hot_rugged_separate"}, {"label": "Quite a few, and honestly nobody's sure what's on them or how secure they are", "next": "result_hot_rugged_unknown"}]}, "unknown_probe": {"type": "problem", "q": "Would it be worth a quick count of how many devices are actually out there, what type they are, and who owns them?", "options": [{"label": "Yes, worth finding out", "next": "result_warm_unknown"}, {"label": "Maybe, if it's quick", "next": "result_mid_unknown"}, {"label": "Not a priority right now", "next": "result_none_unknown"}]}, "result_mid_byod_small": {"result": true, "level": "developing", "title": "Small-Scale BYOD Exposure", "body": "A handful of personal devices accessing company data is a contained but real exposure — manageable to fix before it grows.", "points": ["Ask specifically what they access — email, files, customer data", "Position a lightweight MDM policy now, before the number of devices grows"], "next": "Nurture — easy to fix while the numbers are still small."}, "result_hot_byod_mid": {"result": true, "level": "qualified", "title": "Mid-Scale Mixed BYOD Risk", "body": "A meaningful number of personal devices across mixed platforms with zero management is a real, scaling risk — and it gets harder to fix the longer it's left.", "points": ["Ask what data those devices can actually reach", "Position managed enrolment across both iPhone and Android as the fix"], "next": "Strong opportunity — the scale alone justifies action now."}, "result_hot_byod_large": {"result": true, "level": "qualified", "title": "Business-Wide Unmanaged BYOD", "body": "Most of the business running on personal, unmanaged devices across every platform is one of the largest exposures in the whole mobile estate.", "points": ["Quantify how many devices and how many different platforms are involved", "Position a phased enrolment plan — this is too big to fix in one step"], "next": "Urgent, large-scale opportunity — propose a phased rollout."}, "result_mid_unmanaged_small": {"result": true, "level": "developing", "title": "Small Fleet, No Management", "body": "A small, consistent fleet with no management is a low-effort fix — good opportunity to get ahead of it before the fleet grows.", "points": ["Confirm exactly how many devices and who's responsible for them today", "Position basic MDM enrolment as a quick, low-disruption win"], "next": "Nurture — quick win while the fleet is still small and simple."}, "result_hot_unmanaged_mid": {"result": true, "level": "qualified", "title": "Unmanaged Mixed Fleet", "body": "A decent-sized fleet bought at different times with no management is a real, active exposure with no visibility into patch levels or data access.", "points": ["Ask how the fleet was built up over time — any pattern to device choice?", "Position centralised MDM to bring the whole fleet under one view"], "next": "Strong opportunity — bring the whole fleet under management in one project."}, "result_hot_unmanaged_large": {"result": true, "level": "qualified", "title": "Large Unmanaged Fleet", "body": "A large fleet across multiple device types with zero management is a significant, board-level risk if it were ever tested.", "points": ["Quantify the fleet size precisely — this is a scoping conversation, not just a pitch", "Position a structured rollout, likely phased by site or department"], "next": "Urgent, large-scale opportunity — this needs a proper project plan, not a quick fix."}, "result_none_managed_full": {"result": true, "level": "none", "title": "Fully Enrolled Small Fleet", "body": "Full enrolment across a small, well-managed fleet — genuinely healthy today.", "points": ["Confirm the MDM platform and renewal timeline for future reference"], "next": "Park — revisit at MDM contract renewal or as the fleet grows."}, "result_dev_managed_gaps": {"result": true, "level": "developing", "title": "Mostly Managed, Known Gaps", "body": "Good coverage with a few known gaps — an easy, bounded opportunity to close out rather than a big new sell.", "points": ["Ask specifically which devices are outside management and why", "Position closing the gaps as finishing the job, not starting over"], "next": "Quick-win opportunity — close the specific known gaps."}, "result_hot_managed_shadow": {"result": true, "level": "qualified", "title": "Shadow Devices Outside Management", "body": "A fair number of devices sitting outside management entirely — often the riskiest devices precisely because nobody's watching them.", "points": ["Ask how those devices ended up outside the management platform", "Position a proper audit to find every device, not just the known ones"], "next": "Strong opportunity — an audit alone often justifies the conversation."}, "result_dev_mixed_mostly_managed": {"result": true, "level": "developing", "title": "Mostly Managed, Minor BYOD Tail", "body": "Company devices are the norm with just a handful of personal phones in the mix — a contained, easy-to-close gap.", "points": ["Ask who those few BYOD users are and what they access", "Extend existing management to cover the small remaining tail"], "next": "Quick-win opportunity — extend existing management to the BYOD tail."}, "result_hot_mixed_even": {"result": true, "level": "qualified", "title": "Even Mixed Fleet, No Consistency", "body": "A near-even split between BYOD and company-issued, with no consistent security on either side, is a genuinely complex and real exposure.", "points": ["Map out roughly how many are on each side", "Position a single management policy that covers both ownership models"], "next": "Strong opportunity — a single consistent policy resolves both sides at once."}, "result_hot_mixed_mostly_byod": {"result": true, "level": "qualified", "title": "BYOD-Dominant with Executive Exception", "body": "Mostly BYOD with company phones reserved for senior staff is backwards from a risk perspective — the broader team usually accesses just as much sensitive data.", "points": ["Ask what the broader team can access on their personal phones", "Reframe the conversation around extending protection company-wide, not just to leadership"], "next": "Strong opportunity — reframe protection as a company-wide need, not a leadership perk."}, "result_dev_rugged_small": {"result": true, "level": "developing", "title": "Small Rugged/Field Fleet, Standard Management", "body": "A small number of field devices managed the same way as everyone else — solid practice, worth confirming it holds as the fleet grows.", "points": ["Confirm those devices get the same patch and policy cadence as office staff", "Note the device type for future refresh-cycle conversations"], "next": "Park — revisit at next device refresh cycle."}, "result_hot_rugged_separate": {"result": true, "level": "qualified", "title": "Field Devices Managed Separately", "body": "A meaningful number of field or rugged devices managed outside the normal process is a real, often-overlooked gap — these devices are usually out of sight and out of mind.", "points": ["Ask who currently manages those devices day to day", "Position bringing them into the same management platform as office devices"], "next": "Strong opportunity — consolidate field devices into the main management platform."}, "result_hot_rugged_unknown": {"result": true, "level": "qualified", "title": "Unmanaged Field Fleet, Unknown State", "body": "Nobody being sure what's on those devices or how secure they are is one of the more serious blind spots a business can have — field devices often carry as much sensitive data as anything in the office.", "points": ["Push for a rough count and a sense of what data those devices touch", "Lead with a discovery audit — this is a visibility problem before it's a security problem"], "next": "Urgent opportunity — start with an audit to find out what's actually out there."}, "result_warm_unknown": {"result": true, "level": "developing", "title": "Emerging Opportunity — Needs Discovery", "body": "No visibility into mobile risk today — worth a light audit.", "points": ["Offer a short mobile security check‑in", "Use it to open the wider mobility conversation"], "next": "Book a short discovery call on mobile access and data."}, "result_mid_unknown": {"result": true, "level": "surface", "title": "Time‑Conscious But Open", "body": "Openness exists, but only if the ask is small — respect that constraint to keep the door open.", "points": ["Offer a very short, specific time commitment", "Make the value of the quick look obvious upfront"], "next": "Light nurture — keep the ask small and specific."}, "result_none_unknown": {"result": true, "level": "none", "title": "Follow‑Up Required", "body": "Not a current priority — log and revisit.", "points": ["Set a follow‑up trigger, e.g. next device refresh cycle"], "next": "Log as a future follow‑up."}, "contract_probe": {"type": "problem", "q": "When you upgrade the phones, is the plan to also review what's protecting them — and the rest of your devices — or just swap out the handsets?", "options": [{"label": "Just swapping the handsets, haven't thought about protection", "next": "result_hot_contract"}, {"label": "Thought about it a little, haven't looked into what's actually out there", "next": "result_mid_contract"}, {"label": "We already review that alongside every renewal", "next": "result_none_contract"}]}, "result_hot_contract": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Contract Renewal Is the Moment", "body": "A handset refresh with zero plan for protection is a rare, clean upsell moment — the phones are already being touched, so adding MDM and mobile threat defence is a small ask, not a hard sell.", "points": ["Confirm the renewal or upgrade timing so you can align proposals to it", "Widen the conversation to the rest of the device estate — laptops and desktops often have the same gap, and this is the natural moment to raise EDR too"], "next": "Strong opportunity — bundle MDM, MTD and an EDR conversation into the handset refresh."}, "result_mid_contract": {"result": true, "level": "developing", "title": "Emerging Opportunity — Some Awareness, No Action Yet", "body": "Some awareness that protection matters, but nothing concrete — a good moment to make it simple to say yes to.", "points": ["Offer a short, plain-English rundown of what MDM and mobile threat defence would actually add", "Ask whether laptops and desktops have ever had a proper look for similar protection (EDR)"], "next": "Nurture — make it simple to bolt on protection alongside the upgrade."}, "result_none_contract": {"result": true, "level": "none", "title": "No Immediate Opportunity — Already Sophisticated", "body": "They already treat renewals as a review point — worth confirming what's actually in place rather than assuming a gap.", "points": ["Ask specifically what MDM and threat protection they currently run, to confirm there's genuinely no gap", "Check whether that same discipline extends to laptops and desktops (EDR), not just phones"], "next": "Verify what's actually in place — may still be a gap on the wider device estate."}, "incumbent_probe": {"type": "problem", "q": "How happy are you with them, and do you know roughly when your contract's up?", "options": [{"label": "Not that happy, or not sure when it ends", "next": "result_hot_incumbent"}, {"label": "It's fine, but I've never really compared it to anything else", "next": "result_mid_incumbent"}, {"label": "Very happy, locked in for a good while yet", "next": "result_none_incumbent"}]}, "result_hot_incumbent": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Ready to Switch", "body": "Unhappy with the current provider, or unsure of contract terms, is about as clean a switch opportunity as this gets — lead with the phones and pricing, not a security pitch.", "points": ["Get the exact renewal date and number of lines so a like-for-like comparison is easy to build", "Once the phones and contract conversation lands, that's the natural moment to raise device protection too"], "next": "Strong opportunity — lead with a straightforward like-for-like phones and contract comparison."}, "result_mid_incumbent": {"result": true, "level": "developing", "title": "Emerging Opportunity — Never Compared", "body": "No active complaint, but never benchmarked elsewhere — worth a genuine comparison rather than assuming loyalty.", "points": ["Ask what they're actually paying per line today", "Offer a no-obligation comparison rather than a hard pitch"], "next": "Nurture — offer a simple, no-pressure pricing comparison."}, "result_none_incumbent": {"result": true, "level": "none", "title": "No Immediate Opportunity — Locked In and Happy", "body": "Genuinely happy and locked in — not a live opportunity today.", "points": ["Note their renewal date for a future follow-up"], "next": "Park — revisit closer to their actual renewal date."}}, "situationFollowUp": {"q": "How long has this been the setup, and is anything changing soon — new hires, a device refresh, new roles that need mobiles?", "options": [{"label": "Been like this for a while, nothing changing", "note": "Long-standing mobile setup, no near-term change."}, {"label": "Something's changing soon — hires, a refresh, new roles", "note": "A change is coming that's a natural trigger to revisit mobile."}]}, "implicationFollowUp": {"q": "Beyond what you've mentioned, does this touch anything else — customer data, compliance, or trust if something went wrong publicly?", "options": [{"label": "Yes, it goes wider than that", "note": "The impact extends into customer data, compliance or public trust."}, {"label": "No, that's really it", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "connectivity-access", "name": "Connectivity & Access", "short": "Connectivity", "icon": "🌐", "color": "#C98A2C", "blurb": "Is their internet reliable enough to actually run the business on?", "criteria": ["Connectivity that's actually causing problems day to day", "No backup line — one outage and they're offline", "Growing, or upgrading, without the network behind it keeping up"], "implicationQuestions": {"result_hot_problem": "What does that actually cost you when it happens — lost trading time, frustrated staff, or both?", "result_mid_problem": "Is there a pattern to when it's bad — time of day, specific activities, anything like that?", "result_warm_problem": "Is it getting more noticeable as you add more people or systems onto it?", "result_dev_healthy": "If that single line went down for a full day, what would that actually cost the business?", "result_mid_healthy": "How long does that manual switch typically take once someone notices?", "result_hot_growth": "If connectivity wasn't ready in time for that growth, what would it hold back?", "result_mid_growth": "Who else is involved in that discussion, and what's the timeline looking like?", "result_warm_growth": "Is that new site likely to need the same setup as the others, or something different?", "result_warm_unknown": "If that review turned up you were overpaying or underpowered, what would you want to do about it?", "result_mid_unknown": "Fair enough — would a plain factual summary, no follow-up required, be a fairer way to look at it?", "result_none_unknown": "Is there a renewal or a change coming up that would make this worth another look?", "result_none_healthy": "Good — is there a renewal coming up where it'd be worth checking the failover is still fit for how the business has grown?", "result_hot_lanwan": "If the new line lands but the network behind it can't keep up, what would that actually mean — paying for speed you can't use?", "result_mid_lanwan": "Which part worries you most — the switching, the wiring, or the wireless?", "result_none_lanwan": "Good to know — who actually owns keeping that current as you grow?"}, "needPayoff": {"problem_probe": "If connectivity just worked, reliably, what would that be worth to how the business runs day to day?", "healthy_probe": "If failover meant you never noticed an outage at all, would that be worth the small extra cost?", "growth_probe": "If connectivity scaled smoothly alongside the growth, would that remove one thing to worry about?", "unknown_probe": "If we gave you full clarity on what you're paying for and what you actually need, would that help regardless?", "lanwan_probe": "If we reviewed the LAN/WAN and support alongside the connectivity upgrade, so you actually feel the difference end to end, would that be worth doing together?"}, "tree": {"start": {"type": "situation", "q": "How's your current internet connectivity — reliable enough for everything the business needs, or does it cause problems?", "options": [{"label": "Real problems — slow, drops out, not enough bandwidth", "next": "problem_probe"}, {"label": "It's fine most of the time", "next": "healthy_probe"}, {"label": "We're growing or opening new sites, not sure our plan is right", "next": "growth_probe"}, {"label": "Not sure what we're even on", "next": "unknown_probe"}, {"label": "We're due a connectivity upgrade but haven't looked at the network behind it", "next": "lanwan_probe"}]}, "problem_probe": {"type": "problem", "q": "What's the actual impact — slow systems, dropped calls, can't work at all during outages?", "options": [{"label": "Real business impact — can't work properly", "next": "result_hot_problem"}, {"label": "It's inconsistent — fine some days, bad on others", "next": "result_mid_problem"}, {"label": "Annoying but not critical", "next": "result_warm_problem"}]}, "healthy_probe": {"type": "problem", "q": "Is there any failover if the main line goes down, or would you be offline until it's fixed?", "options": [{"label": "No failover — we'd be offline", "next": "result_dev_healthy"}, {"label": "We have a backup plan but it's manual, not automatic", "next": "result_mid_healthy"}, {"label": "Yes, we have failover", "next": "result_none_healthy"}]}, "growth_probe": {"type": "problem", "q": "How many sites are we talking, and what's driving the growth — new locations, more staff, more cloud usage?", "options": [{"label": "Multiple new sites or a big jump in usage", "next": "result_hot_growth"}, {"label": "Not fully decided yet, but it's being discussed", "next": "result_mid_growth"}, {"label": "Just one more site, fairly modest change", "next": "result_warm_growth"}]}, "unknown_probe": {"type": "problem", "q": "Would it help if I pulled together a quick connectivity review — current speed, contract terms and options?", "options": [{"label": "Yes, that would help", "next": "result_warm_unknown"}, {"label": "Possibly — I just don't want a sales pitch", "next": "result_mid_unknown"}, {"label": "Not a priority right now", "next": "result_none_unknown"}]}, "result_hot_problem": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Connectivity Pain", "body": "Connectivity actively disrupting the business is a strong, easy‑to‑justify pain.", "points": ["Quantify downtime cost — lost trading time, staff idle", "Position Fibre/DIA with firewall failover as the fix"], "next": "Strong opportunity — quantify the pain and propose a resilient connectivity upgrade."}, "result_warm_problem": {"result": true, "level": "developing", "title": "Emerging Opportunity — Minor Connectivity Friction", "body": "Not critical yet, but worth tracking as usage grows.", "points": ["Ask if bandwidth needs are growing — cloud apps, video, backup", "Position as future‑proofing rather than an urgent fix"], "next": "Nurture — revisit as bandwidth demands grow."}, "result_mid_problem": {"result": true, "level": "developing", "title": "Inconsistent Performance", "body": "Inconsistency is often harder to diagnose than a constant problem, and it erodes confidence in the connection over time.", "points": ["Ask if there's a pattern — time of day, specific activities", "An inconsistent line often points to a capacity or contention issue"], "next": "Nurture — investigate the pattern before proposing a fix."}, "result_dev_healthy": {"result": true, "level": "developing", "title": "Emerging Opportunity — No Failover", "body": "Fine day‑to‑day, but a single point of failure is a real exposure.", "points": ["Ask what a full outage would cost per hour", "Introduce 4G/5G failover as low‑cost insurance"], "next": "Low‑friction upsell — position failover as cheap insurance."}, "result_none_healthy": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Reliable connectivity with failover already in place.", "points": ["Confirm contract end date for future reference"], "next": "Park — revisit at contract renewal."}, "result_mid_healthy": {"result": true, "level": "developing", "title": "Manual Failover Only", "body": "Manual failover still means downtime while someone notices and switches over — automatic failover closes that gap.", "points": ["Ask how long the manual switch typically takes", "Position automatic failover as removing the manual delay"], "next": "Upsell — automate what's currently a manual workaround."}, "result_hot_growth": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Growth‑Driven Need", "body": "Significant growth creates a natural, time‑bound connectivity conversation.", "points": ["Map out sites and timelines", "Position cloud infrastructure plus connectivity as scaling with them"], "next": "Strong, time‑bound opportunity — propose a phased connectivity plan for growth."}, "result_warm_growth": {"result": true, "level": "developing", "title": "Emerging Opportunity — Modest Growth", "body": "Some change coming, but not enough to force urgency yet.", "points": ["Get a rough timeline", "Check in closer to the actual move or expansion"], "next": "Nurture — follow up closer to the change."}, "result_mid_growth": {"result": true, "level": "developing", "title": "Growth Under Discussion", "body": "Early‑stage growth planning is a good time to get connectivity right before decisions are locked in elsewhere.", "points": ["Ask who else is involved in the growth planning", "Offer to be part of the planning conversation early"], "next": "Nurture — get involved early, before the growth plan is finalised."}, "result_warm_unknown": {"result": true, "level": "developing", "title": "Emerging Opportunity — Needs Discovery", "body": "No clear picture of current connectivity — a natural audit entry point.", "points": ["Ask for a copy of the current bill or contract", "Use the review to open the wider infrastructure conversation"], "next": "Book a connectivity review as the next step."}, "result_none_unknown": {"result": true, "level": "none", "title": "Follow‑Up Required", "body": "Not a current priority.", "points": ["Set a follow‑up trigger"], "next": "Log as a future follow‑up."}, "result_mid_unknown": {"result": true, "level": "surface", "title": "Cautious But Open", "body": "A specific objection to being sold to — respect it directly and lead with value, not a pitch.", "points": ["Reassure this is a factual review, not a sales call", "Offer to share findings even if there's no follow‑up action"], "next": "Light nurture — lead with value, no strings attached."}, "lanwan_probe": {"type": "problem", "q": "When the new connection goes in, is the LAN/WAN and switching behind it up to the job, or is that ageing too?", "options": [{"label": "Honestly, probably ageing too — hadn't thought about it", "next": "result_hot_lanwan"}, {"label": "Some of it's newer, some isn't — a bit mixed", "next": "result_mid_lanwan"}, {"label": "That's all been kept current alongside connectivity", "next": "result_none_lanwan"}]}, "result_hot_lanwan": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Upgrade Without a Modern Network Behind It", "body": "A faster connection landing on ageing LAN/WAN and switching is a classic case of the upgrade not actually being felt — a natural moment to scope both together.", "points": ["Ask what's actually running the internal network today — age of switches, wiring, wireless", "Position reviewing LAN/WAN and support alongside the connectivity upgrade, not as a separate project"], "next": "Strong opportunity — bundle a LAN/WAN and support review into the connectivity upgrade."}, "result_mid_lanwan": {"result": true, "level": "developing", "title": "Emerging Opportunity — Partially Modernised", "body": "A mixed picture is a good entry point — there's already an appetite to modernise, just not finished yet.", "points": ["Ask specifically which parts are older and why they haven't been touched yet", "Offer a quick review to identify the weakest link before the new connection goes live"], "next": "Nurture — offer a quick review to find the weakest link."}, "result_none_lanwan": {"result": true, "level": "none", "title": "No Immediate Opportunity — Already Modernised", "body": "LAN/WAN already kept current alongside connectivity — not a live gap today.", "points": ["Note their refresh cycle for future reference"], "next": "Park — revisit near their next refresh cycle."}}, "situationFollowUp": {"q": "How long has connectivity been set up this way, and is anything changing — growth, a new site, more cloud usage?", "options": [{"label": "Been like this for years, nothing changing", "note": "Long-standing connectivity setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit connectivity."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've mentioned — customer experience, staff productivity, or other systems relying on it?", "options": [{"label": "Yes, it touches other things too", "note": "The impact extends beyond the immediate connectivity issue."}, {"label": "No, that's really it", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "cyber-assurance", "name": "Cyber Assurance", "short": "Cyber Assurance", "icon": "🛡", "color": "#8B3A3A", "blurb": "Do they have a real security plan, or just some tools and a hope?", "criteria": ["Security tools exist, but nobody actually owns the overall plan", "No tested plan for what happens if something goes wrong", "A customer, regulator, or competitor is pushing them to prove their security is solid", "Nobody's actually watching for threats day to day"], "implicationQuestions": {"result_mid_tools_gov": "If a serious alert came in tonight, who actually has the authority to decide what happens next?", "result_hot_tools_noplan": "If tools alone were enough, why do so many breaches still happen at businesses with tools in place?", "result_none_governed": "Good — when was that governance model last actually tested against a live scenario?", "result_hot_incident_noplan": "Without a documented plan, how much of that response last time was improvised on the spot?", "result_mid_incident_informal": "If the same incident happened again next month, would the response look any more organised?", "result_warm_noincident": "If an incident did happen tomorrow, who in the business would actually take charge of the response?", "result_hot_noleader_growing": "As the business keeps growing, what's the cost of security decisions continuing to be made without anyone owning them properly?", "result_mid_noleader_adhoc": "When something security-related needs a real decision, who ends up making the call today?", "result_dev_noleader_confident": "If that confidence turned out to be based on assumptions rather than a real review, how would you find out?", "result_hot_compliance_pressure": "What happens to the business relationship if you can't demonstrate that governance when asked?", "result_mid_compliance_unsure": "If a customer or insurer asked for evidence of this tomorrow, could you produce it today?", "result_none_compliance_covered": "Good — is that reviewed on a schedule, or was it done once for a specific deal and left alone?", "result_hot_competitive_newbiz": "How many deals do you reckon have stalled or been lost over this specifically?", "result_dev_competitive_reassure": "If a customer asked and you couldn't answer confidently, what would that do to the relationship?", "result_dev_competitive_ahead": "If a competitor won a deal specifically because they could show this and you couldn't, how would that feel?", "ms_result_hot_reactive": "By the time it breaks or locks up, how much damage could already be done — data taken, downtime, or both?", "ms_result_mid_reactive": "In a day or two of unnoticed access, what could someone actually do?", "ms_result_warm_reactive": "How quickly is 'fairly quickly', realistically — hours, or could it be days?", "ms_result_hot_partial": "What kind of threat would get through antivirus but wouldn't get caught by something more modern?", "ms_result_mid_partial": "If it turned out that bundled protection was lighter than you thought, would that be worth knowing?", "ms_result_warm_partial": "If we found a gap in there, how would that change how you feel about it?", "ms_result_dev_healthy": "If a compromised login or a firewall alert went unnoticed because it's not part of the same picture, what could that lead to?", "ms_result_mid_healthy": "If a firewall alert went off right now, who would actually see it?", "ms_result_hot_incident": "If that exact thing happened again tomorrow, what would it cost you this time round?", "ms_result_mid_incident": "What's been competing for priority — and is this still worth bumping up the list?", "ms_result_hot_incident_partial": "For whatever's still not covered, is that the same gap that caused the original incident, or something different?", "ms_result_none_healthy": "Good — is that reviewed against new threat types regularly, or was it set up once and left running?"}, "needPayoff": {"tools_probe": "If governance and decision-making sat on top of the tools you already have, would that close the gap?", "incident_probe": "If you had a tested plan and a clear owner before the next incident, would that change how confident you feel today?", "noleader_probe": "If you had access to senior security leadership without hiring a full-time executive, would that solve it?", "compliance_probe": "If you could produce clear evidence of governance whenever it's asked for, would that remove the risk?", "competitive_probe": "If you could confidently show customers and prospects exactly how security is governed here, would that change conversations you're currently finding difficult?", "ms_reactive_probe": "If you had eyes on this 24/7 instead of finding out after the fact, what would that change?", "ms_partial_probe": "If EDR sat on top of what you already have, would that close the gap without a big disruption?", "ms_healthy_probe": "If identity and firewall were pulled into the same picture as your endpoints, would that complete it?", "ms_incident_probe": "If we made sure that specific gap couldn't be exploited again, how much would that be worth?"}, "tree": {"start": {"type": "situation", "q": "How does security get managed day to day — is it just the tools you have, or is there someone actively steering it?", "options": [{"label": "We've tools in place — firewall, antivirus, backups — but no one really steering the overall picture", "next": "tools_probe"}, {"label": "We've had a security incident or scare and had to figure out the response as we went", "next": "incident_probe"}, {"label": "Nobody in the business has real security leadership — it's whoever's free at the time", "next": "noleader_probe"}, {"label": "A customer, insurer or regulation is starting to ask us questions we can't easily answer", "next": "compliance_probe"}, {"label": "We want to be able to demonstrate our security credentials — to win business, reassure customers, or stand out from competitors", "next": "competitive_probe"}, {"label": "We'd only find out after something went wrong", "next": "ms_reactive_probe"}, {"label": "We have some monitoring or antivirus but nothing 24/7", "next": "ms_partial_probe"}, {"label": "We have proper 24/7 monitoring already", "next": "ms_healthy_probe"}, {"label": "We've had a security incident before", "next": "ms_incident_probe"}]}, "tools_probe": {"type": "problem", "q": "Is there someone who owns the overall security picture — setting priorities, reviewing risk, making the calls — or does it stop at the tools themselves?", "options": [{"label": "There's some oversight, but it's informal and reactive", "next": "result_mid_tools_gov"}, {"label": "Honestly, it stops at the tools — nobody owns the bigger picture", "next": "result_hot_tools_noplan"}, {"label": "Yes, someone actively governs it and reviews risk regularly", "next": "result_none_governed"}]}, "incident_probe": {"type": "problem", "q": "When that happened, was there a documented plan to follow, or was the response worked out on the spot?", "options": [{"label": "No plan — entirely improvised in the moment", "next": "result_hot_incident_noplan"}, {"label": "Something informal existed, but it wasn't really followed properly", "next": "result_mid_incident_informal"}, {"label": "We haven't actually had a real incident, just a scare", "next": "result_warm_noincident"}]}, "noleader_probe": {"type": "problem", "q": "As the business has grown, has that gap in ownership stayed about the same, or is it becoming more noticeable?", "options": [{"label": "It's becoming more noticeable as we grow", "next": "result_hot_noleader_growing"}, {"label": "It's whoever's around at the time — no real pattern", "next": "result_mid_noleader_adhoc"}, {"label": "We're fairly confident in how it's handled today", "next": "result_dev_noleader_confident"}]}, "compliance_probe": {"type": "problem", "q": "Is that pressure tied to a specific deal, contract or renewal, or is it becoming a more general expectation?", "options": [{"label": "It's tied to a specific deal or contract we don't want to lose", "next": "result_hot_compliance_pressure"}, {"label": "Not sure we could produce what's actually being asked for", "next": "result_mid_compliance_unsure"}, {"label": "We already have something in place that covers this", "next": "result_none_compliance_covered"}]}, "result_mid_tools_gov": {"result": true, "level": "developing", "title": "Informal, Reactive Oversight", "body": "Some oversight exists but it's reactive rather than structured — governance that only shows up after something's already gone wrong.", "points": ["Ask what triggered oversight the last time it happened", "Position structured, ongoing governance rather than reactive attention"], "next": "Nurture — position proactive governance as the next step up."}, "result_hot_tools_noplan": {"result": true, "level": "qualified", "title": "Tools Without Governance", "body": "Security tools with nobody steering the overall picture is one of the most common and least visible gaps — the tools give a false sense of coverage.", "points": ["Ask who would make the call if two tools gave conflicting signals", "Position leadership and governance as completing what the tools already do"], "next": "Strong opportunity — the gap is real even though it doesn't feel urgent day to day."}, "result_none_governed": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Genuine, active governance already in place — healthy today.", "points": ["Confirm how that governance is resourced, for future reference"], "next": "Park — revisit if the person doing this role ever changes."}, "result_hot_incident_noplan": {"result": true, "level": "qualified", "title": "Incident Handled With No Plan", "body": "Improvising a response to a real incident is high-risk and usually more costly and slower than it needed to be — a strong, concrete trigger.", "points": ["Ask how much longer the response took without a plan to follow", "Position a documented, tested incident response plan as preventing a repeat"], "next": "Urgent opportunity — use the real incident directly to justify action."}, "result_mid_incident_informal": {"result": true, "level": "developing", "title": "Informal Plan, Not Followed", "body": "Something existed on paper but didn't hold up in practice — a plan that isn't tested is barely better than no plan.", "points": ["Ask specifically where the informal plan broke down", "Position regular testing and review as what turns a document into a real capability"], "next": "Nurture — position testing and review as the missing piece."}, "result_warm_noincident": {"result": true, "level": "developing", "title": "Scare But No Real Incident Yet", "body": "A scare without a full incident is a valuable, low-cost warning — the business hasn't paid the full price of being unprepared yet.", "points": ["Ask what the scare revealed about current readiness", "Use the scare as a preview, not a closed chapter"], "next": "Nurture — use the scare as the trigger before a real incident forces the issue."}, "result_hot_noleader_growing": {"result": true, "level": "qualified", "title": "Growing Business, No Security Leadership", "body": "A widening gap between business growth and security leadership is a strong, time-sensitive opportunity — the risk compounds as the business scales.", "points": ["Ask what's changed in the business that makes this more pressing now", "Position senior security leadership as scaling alongside the business, not behind it"], "next": "Strong, time-bound opportunity — growth itself is the trigger."}, "result_mid_noleader_adhoc": {"result": true, "level": "developing", "title": "Ad Hoc Ownership", "body": "Whoever's free making security calls is a fragile model — works until the wrong moment, then doesn't.", "points": ["Ask what happens when nobody's available to make the call", "Position clear, consistent ownership as removing the fragility"], "next": "Nurture — highlight the risk of decisions depending on availability, not expertise."}, "result_dev_noleader_confident": {"result": true, "level": "developing", "title": "Confident, But Unverified", "body": "Confidence without a recent independent review is exactly the kind of gap that only becomes visible after something goes wrong.", "points": ["Ask when the current approach was last independently reviewed", "Offer a light-touch review to confirm the confidence is well-founded"], "next": "Nurture — offer a review to validate or challenge existing confidence."}, "result_hot_compliance_pressure": {"result": true, "level": "qualified", "title": "Deal-Driven Compliance Pressure", "body": "Pressure tied to a specific deal or contract creates real urgency — and a very concrete reason to act now rather than eventually.", "points": ["Confirm exactly what's being asked for and by when", "Position a fast, structured governance package to meet the specific requirement"], "next": "Urgent, deal-driven opportunity — there's a real deadline to work against."}, "result_mid_compliance_unsure": {"result": true, "level": "developing", "title": "Uncertain Evidence Readiness", "body": "Not being sure you could produce evidence of governance is itself a gap worth closing before it's tested by someone outside the business.", "points": ["Ask exactly what's likely to be asked for, and by whom", "Offer to help build the evidence base before it's needed under pressure"], "next": "Nurture — get ahead of the ask before an external party forces the timeline."}, "result_none_compliance_covered": {"result": true, "level": "none", "title": "Already Covered", "body": "Something's already in place that addresses this — worth confirming it's still current.", "points": ["Confirm when that was last reviewed or updated"], "next": "Park — revisit at next renewal or review cycle."}, "competitive_probe": {"type": "problem", "q": "Is that mainly about winning new business, reassuring existing customers, or getting ahead of competitors who are already doing this?", "options": [{"label": "Winning new business — we keep getting asked before contracts are signed", "next": "result_hot_competitive_newbiz"}, {"label": "Reassuring existing customers who are starting to ask more questions", "next": "result_dev_competitive_reassure"}, {"label": "Getting ahead of competitors — we know some of them already have this", "next": "result_dev_competitive_ahead"}]}, "result_hot_competitive_newbiz": {"result": true, "level": "qualified", "title": "Security as a Deal-Winning Differentiator", "body": "Being asked for security credentials before contracts close means this directly affects revenue, not just risk — a strong, commercially-driven reason to act.", "points": ["Ask how many deals have stalled or been asked about this recently", "Position a clear, presentable security and governance story as a sales enabler, not just a defensive measure"], "next": "Strong, commercially-driven opportunity — frame this as revenue protection, not just risk reduction."}, "result_dev_competitive_reassure": {"result": true, "level": "developing", "title": "Reassuring an Increasingly Curious Customer Base", "body": "Customers asking more questions is an early signal, not yet a crisis — a good moment to get ahead of it before it becomes a blocker.", "points": ["Ask what prompted customers to start asking", "Offer a clear, simple way to answer those questions confidently"], "next": "Nurture — get ahead of rising customer expectations before they become a blocker."}, "result_dev_competitive_ahead": {"result": true, "level": "developing", "title": "Competitive Catch-Up", "body": "Knowing competitors already have this is a good motivator, but without a specific deal or customer driving it, the urgency is more strategic than immediate.", "points": ["Ask which competitors, and how they know", "Position this as a strategic differentiator to get ahead of, not just match"], "next": "Nurture — position as getting ahead, not just catching up."}, "ms_reactive_probe": {"type": "problem", "q": "How would that discovery actually happen — a customer complaint, a locked‑out system, something else?", "options": [{"label": "Realistically, when something breaks or locks up", "next": "ms_result_hot_reactive"}, {"label": "Somewhere in between — we'd probably notice within a day or two", "next": "ms_result_mid_reactive"}, {"label": "We'd probably notice fairly quickly some other way", "next": "ms_result_warm_reactive"}]}, "ms_partial_probe": {"type": "problem", "q": "Does that cover endpoint detection and response, or is it more traditional antivirus?", "options": [{"label": "Traditional antivirus only, no EDR", "next": "ms_result_hot_partial"}, {"label": "Not sure — it came bundled with something else", "next": "ms_result_mid_partial"}, {"label": "Not sure what level of protection it really is", "next": "ms_result_warm_partial"}]}, "ms_healthy_probe": {"type": "problem", "q": "Great — does that also cover identity risk, like risky M365 sign‑ins, and firewall alert correlation, or just endpoints?", "options": [{"label": "Just endpoints, not identity or firewall", "next": "ms_result_dev_healthy"}, {"label": "Identity yes, but not firewall correlation", "next": "ms_result_mid_healthy"}, {"label": "Yes, fully integrated across the board", "next": "ms_result_none_healthy"}]}, "ms_incident_probe": {"type": "problem", "q": "What was the root cause, and what's changed in your monitoring since then?", "options": [{"label": "Not much has changed since the incident", "next": "ms_result_hot_incident"}, {"label": "We meant to review it properly but it kept getting deprioritised", "next": "ms_result_mid_incident"}, {"label": "We improved some things but it's patchy", "next": "ms_result_hot_incident_partial"}]}, "ms_result_hot_reactive": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Active Monitoring", "body": "Finding out only after something breaks is a high‑risk, high‑urgency gap — easy to build a case around.", "points": ["Walk through the cost and impact of a realistic incident going undetected", "Position 24/7 monitored protection (a security operations centre watching in real time, sometimes called a SOC) as closing the detection gap"], "next": "Urgent — this is a foundational gap, propose 24/7 monitored protection directly."}, "ms_result_warm_reactive": {"result": true, "level": "developing", "title": "Emerging Opportunity — Some Informal Detection", "body": "Some visibility exists informally, but it's not systematic — needs quantifying.", "points": ["Ask how long that informal detection usually takes", "Reframe time‑to‑detect as the real risk"], "next": "Nurture — quantify the detection gap to build urgency."}, "ms_result_mid_reactive": {"result": true, "level": "developing", "title": "Delayed Detection", "body": "A day or two of dwell time is still a long window for an attacker to do damage — much better than nothing, but far from real‑time.", "points": ["Ask what a day or two of unnoticed access could actually lead to", "Frame 24/7 monitoring as closing that specific window"], "next": "Nurture — quantify what could happen in that detection window."}, "ms_result_hot_partial": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Antivirus‑Only Gap", "body": "Traditional AV without EDR misses modern threats — a clear capability gap to close.", "points": ["Explain the difference simply: traditional antivirus only blocks known viruses, EDR watches for suspicious behaviour too", "Position EDR as an upgrade path, not a rip‑and‑replace"], "next": "Strong opportunity — position EDR as a natural upgrade."}, "ms_result_warm_partial": {"result": true, "level": "developing", "title": "Emerging Opportunity — Unclear Coverage", "body": "Uncertainty about the current protection level is itself a discovery opportunity.", "points": ["Offer a quick security posture review", "Use the findings to shape the proposal"], "next": "Nurture — offer a security posture review to clarify the gap."}, "ms_result_mid_partial": {"result": true, "level": "surface", "title": "Unknown Bundled Protection", "body": "Bundled security tools are often under‑configured or lower‑tier than they appear — worth a proper check.", "points": ["Offer to identify exactly what's included", "Use the finding either way as the basis for a recommendation"], "next": "Light nurture — clarify exactly what's actually protecting them."}, "ms_result_dev_healthy": {"result": true, "level": "developing", "title": "Emerging Opportunity — Partial Coverage", "body": "Endpoint coverage exists, but identity and firewall visibility are missing pieces.", "points": ["Ask about visibility into M365 risky sign‑ins specifically", "Position identity and firewall visibility as closing the remaining gaps"], "next": "Upsell opportunity — extend existing coverage to identity and firewall."}, "ms_result_none_healthy": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Comprehensive, integrated security monitoring already in place.", "points": ["Confirm provider and renewal date for competitive tracking"], "next": "Park — revisit at renewal or if incidents occur elsewhere in their sector."}, "ms_result_mid_healthy": {"result": true, "level": "developing", "title": "Identity Covered, Firewall Gap", "body": "Partial integration still leaves blind spots — an alert on the firewall side could go unnoticed even with good identity coverage.", "points": ["Ask how firewall alerts get handled today, if at all", "Position firewall correlation as completing the picture"], "next": "Upsell — close the specific firewall visibility gap."}, "ms_result_hot_incident": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Post‑Incident, No Change", "body": "A real incident with no real change since is a strong, urgent trigger.", "points": ["Use the incident directly to justify budget", "Position 24/7 monitoring as preventing a repeat"], "next": "Fast‑track — same‑quarter opportunity, lead with preventing a repeat."}, "ms_result_hot_incident_partial": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Post‑Incident, Partial Fix", "body": "Improvements were made but coverage is still patchy — a strong opportunity to complete the picture.", "points": ["Ask specifically what's still not covered", "Position a fully monitored, round-the-clock layer to close the remaining gaps"], "next": "Strong opportunity — identify and close the remaining gaps."}, "ms_result_mid_incident": {"result": true, "level": "developing", "title": "Good Intentions, No Action", "body": "Intent without action after a real incident is a classic gap — they know it matters, they just haven't gotten to it.", "points": ["Ask what's been competing for priority", "Offer to make this the easy option rather than another big project"], "next": "Nurture — make action easier than continuing to defer it."}}, "situationFollowUp": {"q": "How long has security been handled this way, and is anything changing — new customers, a new regulation, growth that's stretching things?", "options": [{"label": "Been like this for a long time, no changes", "note": "Long-standing approach to security, no near-term change."}, {"label": "Things are changing — new customers, regulation, growth", "note": "Change is coming that raises the stakes on this gap."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've said — customer trust, contracts, or how the business would be perceived if it became public?", "options": [{"label": "Yes, it goes wider than that", "note": "The impact reaches into trust, contracts or public perception."}, {"label": "No, that's really the whole picture", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "m365", "name": "Microsoft 365 Modern Work", "short": "Microsoft 365", "icon": "🧩", "color": "#2C6FB0", "blurb": "Are they using Microsoft 365 properly and securely, or just the basics?", "criteria": ["Not on Microsoft 365, or on the wrong plan for what they need", "Logins aren't properly locked down (no MFA)", "They're in a sector where a security gap is a real compliance risk"], "implicationQuestions": {"result_hot_switch": "What's it costing you to stay on what you've got — security gaps, compatibility issues, or just staff frustration?", "result_mid_switch": "If that informal use got flagged in an audit or a client review, what would that expose you to?", "result_warm_switch": "What actually went wrong last time — was it the rollout, the training, or something else?", "result_hot_misaligned": "What's that actually exposing you to, or costing you in wasted licence spend each month?", "result_mid_misaligned": "If one of those gaps did get exploited, what would that realistically look like for the business?", "result_warm_misaligned": "What would getting proper value out of what you're already paying for be worth to you?", "result_dev_healthy": "If one account without MFA got compromised, what could someone actually reach from there?", "result_mid_healthy": "Who are the exceptions, typically — the accounts with the most access, or the least?", "result_warm_unknown": "If that review turned up something serious, how quickly would you want to act on it?", "result_mid_unknown": "What would make this feel like a five-minute favour instead of a big commitment?", "result_none_unknown": "Who's the right person to loop in, and what would you need from me to make that easy for them?", "result_none_healthy": "Good — is there a renewal or a headcount change coming up where it'd be worth double-checking that's all still locked down?"}, "needPayoff": {"notonm365_probe": "If the switch was managed properly with training included, would that remove the hesitation?", "misaligned_probe": "If your licences and security were properly aligned to what you actually need, what would that free up?", "healthy_probe": "If MFA and Conditional Access were locked down everywhere, would that close the gap you're describing?", "unknown_probe": "If we gave you a clear picture of exactly what you're paying for and how secure it really is, would that help?"}, "tree": {"start": {"type": "situation", "q": "How's Microsoft 365 set up for you today — are you on the right licences, does it feel joined up, or a bit patchwork?", "options": [{"label": "We're not on M365 — still on old Office or Google", "next": "notonm365_probe"}, {"label": "We have it, but might be on the wrong licences or underusing it", "next": "misaligned_probe"}, {"label": "We have it and it mostly works fine", "next": "healthy_probe"}, {"label": "Not sure what licences we're even on", "next": "unknown_probe"}]}, "notonm365_probe": {"type": "problem", "q": "What's driving that — cost, inertia, or a specific reason you've stayed away?", "options": [{"label": "Just never got around to switching", "next": "result_hot_switch"}, {"label": "We use some of it but not properly licensed or rolled out", "next": "result_mid_switch"}, {"label": "Tried it before and it didn't go well", "next": "result_warm_switch"}]}, "misaligned_probe": {"type": "problem", "q": "What's not working — things like login protection and access rules, collaboration tools like Teams and SharePoint, or just paying for licences you don't use?", "options": [{"label": "Security gaps or paying for the wrong tier", "next": "result_hot_misaligned"}, {"label": "Probably a bit of both, but nothing's actually gone wrong", "next": "result_mid_misaligned"}, {"label": "Just underusing it, not urgent", "next": "result_warm_misaligned"}]}, "healthy_probe": {"type": "problem", "q": "Good — does everyone have to confirm their identity with a code or app when logging in (not just a password), and are company devices managed centrally?", "options": [{"label": "Not sure, or probably not fully", "next": "result_dev_healthy"}, {"label": "Enforced for most people, but a few exceptions exist", "next": "result_mid_healthy"}, {"label": "Yes, that's all locked down", "next": "result_none_healthy"}]}, "unknown_probe": {"type": "problem", "q": "Would it help if I ran a quick licence and security review with whoever manages your Microsoft tenant?", "options": [{"label": "Yes, that would help", "next": "result_warm_unknown"}, {"label": "Maybe — depends what it would involve", "next": "result_mid_unknown"}, {"label": "I'd need to check with someone first", "next": "result_none_unknown"}]}, "result_hot_switch": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Ready to Move to M365", "body": "No real objection, just inertia — one of the easiest wins in the portfolio.", "points": ["Map their current tools to Business Basic, Standard or Premium", "Lead with email, Teams and SharePoint as the foundation"], "next": "Fast‑moving opportunity — propose a phased migration."}, "result_warm_switch": {"result": true, "level": "developing", "title": "Emerging Opportunity — Past Bad Experience", "body": "A previous failed rollout needs addressing before they'll trust a second attempt.", "points": ["Ask what specifically went wrong last time", "Reassure with a managed, phased approach and proper training"], "next": "Nurture — address the trust gap before proposing again."}, "result_mid_switch": {"result": true, "level": "developing", "title": "Partial, Unlicensed Adoption", "body": "Using M365 tools without proper licensing or rollout usually means missing security features and compliance risk.", "points": ["Ask exactly what's being used informally", "Position a proper licensed rollout as closing gaps they may not know exist"], "next": "Strong nurture — often reveals more exposure than a clean 'not on M365' case."}, "result_hot_misaligned": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Security or Licensing Gap", "body": "Security gaps or licence waste are both budget‑justifiable and urgent.", "points": ["Quantify spend wasted on unused licences", "Highlight extra login protection (a code or app on top of a password, sometimes called MFA) as a quick, high-impact fix"], "next": "Strong opportunity — lead with a licence and security audit."}, "result_warm_misaligned": {"result": true, "level": "developing", "title": "Emerging Opportunity — Underused, Not Urgent", "body": "Underuse alone rarely creates urgency — needs a business reason to fix.", "points": ["Ask what they're actually trying to get better at", "Tie a specific M365 pillar to that goal"], "next": "Nurture — connect to a specific business goal before proposing."}, "result_mid_misaligned": {"result": true, "level": "developing", "title": "Likely Gaps, No Trigger Yet", "body": "Self‑awareness of a gap without an incident is a great foundation — just needs a reason to prioritise it.", "points": ["Ask what would need to happen for this to become urgent", "Offer a no‑pressure review to quantify the gap"], "next": "Nurture — offer a review to turn vague awareness into a clear case."}, "result_dev_healthy": {"result": true, "level": "developing", "title": "Emerging Opportunity — Security Posture Gap", "body": "Generally happy, but security fundamentals may be missing — a real but quiet risk.", "points": ["Offer a free login-security and device-management health check", "Frame it as protecting what already works"], "next": "Low‑friction entry — offer a security health check."}, "result_none_healthy": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "M365 is well set up and secured already.", "points": ["Confirm renewal date and licence mix for future reference"], "next": "Park — revisit at renewal or if headcount grows."}, "result_mid_healthy": {"result": true, "level": "developing", "title": "Mostly Enforced, Exceptions Exist", "body": "Security is only as strong as its weakest exception — a few unprotected accounts can undermine an otherwise solid setup.", "points": ["Ask who the exceptions are and why", "Closing exceptions is usually a quick, low‑cost fix"], "next": "Quick‑win opportunity — close the specific exceptions."}, "result_warm_unknown": {"result": true, "level": "developing", "title": "Emerging Opportunity — Needs Discovery", "body": "No clear picture of current state — a natural audit entry point.", "points": ["Book time with whoever manages the tenant", "Use the audit to uncover licensing and security gaps"], "next": "Book a licence and security review as the next step."}, "result_none_unknown": {"result": true, "level": "none", "title": "Follow‑Up Required", "body": "Not enough information to qualify yet.", "points": ["Ask them to loop in the right person", "Set a specific follow‑up date"], "next": "Log as a follow‑up — not yet qualified."}, "result_mid_unknown": {"result": true, "level": "surface", "title": "Cautiously Open", "body": "Some hesitancy, but not a hard no — worth making the review low‑friction to remove the barrier.", "points": ["Explain exactly what the review would involve and take", "Keep the ask small — a short call, not a big commitment"], "next": "Light nurture — lower the barrier to a very small first step."}}, "situationFollowUp": {"q": "How long has it been set up this way, and is anything changing soon — headcount, a new office, a compliance requirement?", "options": [{"label": "Long-standing setup, nothing changing", "note": "Stable, long-standing M365 setup with no near-term change."}, {"label": "Something's changing that could affect this", "note": "A change is coming that's a natural trigger to revisit M365."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've said — client trust, compliance, or time lost by the team working around it?", "options": [{"label": "Yes, it affects other things too", "note": "The impact extends into trust, compliance or team time."}, {"label": "No, that's the whole story", "note": "The impact stays contained to what's already been discussed."}]}}, {"id": "secure-network", "name": "Secure SME Networking", "short": "Secure Network", "icon": "🛡️", "color": "#23283C", "blurb": "Is their network fast, reliable, and actually secure?", "criteria": ["Wi-Fi or network problems that actually slow the business down", "A security scare, or a close call, already happened", "One flat network with no one really in charge of it"], "implicationQuestions": {"result_dev_seg": "With everything on one network, if a guest device or a compromised camera got onto it, what else could it reach — POS, staff files, everything?", "result_mid_seg": "For whatever's still mixed in with the rest, what would it take for something on that side to cause a problem elsewhere?", "result_none_healthy": "Good — is there anything on the roadmap, like new IoT devices or a new site, that might complicate that segmentation later?", "result_hot_reliability": "With that happening weekly, what does it actually cost you over a month — in lost trading time, idle staff, or missed calls?", "result_mid_reliability": "Even with the improvement, what still happens on the odd occasion it does act up?", "result_warm_reliability": "Even if it's just occasional, what does it cost you on the day it happens?", "result_hot_incident": "Since that incident, what's actually changed — or is the same exposure still sitting there?", "result_mid_incident": "If that suspicious activity had gone further and turned into something confirmed, what would that have meant for the business?", "result_warm_incident": "What's driving that worry specifically — is there something that would make it feel more real if it happened?", "result_hot_ownership": "With nobody specifically owning it, what's the longest something's ever sat broken before someone noticed?", "result_mid_ownership": "When they're stretched thin, what tends to slip — patching, monitoring, or just slower response times?", "result_warm_ownership": "How happy are you with how quickly they respond when something does come up?"}, "needPayoff": {"seg_check": "If we could separate guest and IoT traffic from your core systems without disrupting anything, would that close the gap?", "reliability_probe": "If outages like that stopped happening altogether, what would that be worth to the business over a year?", "security_probe": "If you had eyes on the network so this couldn't happen again unnoticed, how much would that change things?", "ownership_probe": "If there was one number to call and one team accountable end to end, how much simpler would that be?"}, "tree": {"start": {"type": "situation", "q": "Tell me about your current network and Wi‑Fi — how's it holding up day to day?", "options": [{"label": "No real issues that I know of", "next": "seg_check"}, {"label": "We get outages, dropouts or slow Wi‑Fi", "next": "reliability_probe"}, {"label": "We're concerned about security, or we've had an incident", "next": "security_probe"}, {"label": "Honestly not sure — someone else looks after it", "next": "ownership_probe"}]}, "seg_check": {"type": "problem", "q": "Good to hear. Is the network segmented — guest Wi‑Fi, CCTV/IoT and staff systems kept apart — or is everything on one flat network?", "options": [{"label": "Everything's on one network", "next": "result_dev_seg"}, {"label": "Partially — some separation, but it's inconsistent", "next": "result_mid_seg"}, {"label": "Yes, it's segmented properly", "next": "result_none_healthy"}]}, "reliability_probe": {"type": "problem", "q": "How often does that happen, and what does it actually stop people doing when it does?", "options": [{"label": "Weekly or more — tills, calls or systems go down", "next": "result_hot_reliability"}, {"label": "It happens, but it's improved since we made some changes", "next": "result_mid_reliability"}, {"label": "Only occasionally, more of an annoyance", "next": "result_warm_reliability"}]}, "security_probe": {"type": "problem", "q": "Was that an actual incident — phishing, ransomware, unauthorised access — or more a general worry? What happened?", "options": [{"label": "We had a real incident", "next": "result_hot_incident"}, {"label": "We've seen suspicious activity but nothing confirmed", "next": "result_mid_incident"}, {"label": "General worry, no incident yet", "next": "result_warm_incident"}]}, "ownership_probe": {"type": "problem", "q": "Who actually manages it today — internal IT, an outsourced provider, or is it a bit ad hoc?", "options": [{"label": "Nobody specific / ad hoc", "next": "result_hot_ownership"}, {"label": "It's technically someone's job, but they're stretched thin", "next": "result_mid_ownership"}, {"label": "An MSP or internal IT manages it", "next": "result_warm_ownership"}]}, "result_none_healthy": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Network sounds stable and segmented — there's no active pain to lead with today.", "points": ["Keep this on file for a lifecycle/renewal conversation", "Ask who supplies their firewall/support and when it's up for renewal"], "next": "Park this area — revisit at contract renewal or if they mention growth or new sites."}, "result_dev_seg": {"result": true, "level": "developing", "title": "Emerging Opportunity — Segmentation Gap", "body": "No major complaints, but a flat network with CCTV/IoT and staff together is a real exposure — a silent risk rather than a felt one.", "points": ["Ask exactly what's on the network — CCTV, EPOS, guest Wi‑Fi", "Introduce VLAN segmentation as good practice, not a fire to put out"], "next": "Position Secure SME Networking as a proactive upgrade — nurture, don't push."}, "result_mid_seg": {"result": true, "level": "surface", "title": "Partial Segmentation", "body": "Some separation exists but it's inconsistent — not flat, but not properly isolated either.", "points": ["Ask which systems specifically aren't separated yet", "Position full VLAN segmentation as finishing the job, not starting from scratch"], "next": "Light nurture — position as completing something already started."}, "result_hot_reliability": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Reliability Pain", "body": "Frequent outages with real business impact — lost trading time, staff sitting idle — is a strong, fundable pain.", "points": ["Quantify the cost of downtime per incident (staff hours, lost sales)", "Position FortiGate plus FortiExtender 5G backup WAN as the fix"], "next": "Move to a site survey or proposal — this is fundable pain with a clear ROI story."}, "result_warm_reliability": {"result": true, "level": "developing", "title": "Emerging Opportunity — Minor Reliability Issues", "body": "Some friction but not painful enough to act on yet — worth tracking.", "points": ["Ask if it's getting more frequent as they add devices or staff", "Introduce backup WAN as insurance rather than urgency"], "next": "Nurture — check back next quarter or after the next disruption."}, "result_mid_reliability": {"result": true, "level": "surface", "title": "Improving But Not Resolved", "body": "They've already taken some action, which shows awareness — but the underlying issue likely isn't fully fixed.", "points": ["Ask exactly what changes were made and whether they've fully stopped the issue", "Position a proper fix as finishing what they started, not criticising their effort"], "next": "Nurture — acknowledge their progress, then probe for what's still unresolved."}, "result_hot_incident": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Security Incident", "body": "A real incident is one of the strongest triggers in the whole portfolio — there's likely already leadership attention on it.", "points": ["Ask what's changed since the incident — any remediation done yet?", "Bring Managed Security (SOC/EDR) into the same conversation"], "next": "Fast‑track this — same‑quarter opportunity, loop in Managed Security."}, "result_warm_incident": {"result": true, "level": "developing", "title": "Emerging Opportunity — Security Concern, No Incident", "body": "Awareness without a trigger event — this needs a reason to act now.", "points": ["Ask what's prompting the worry — news, a customer or insurer requirement?", "Offer a free network/security health check to create the trigger"], "next": "Offer a light‑touch audit to convert concern into qualified pain."}, "result_mid_incident": {"result": true, "level": "developing", "title": "Suspicious Activity, Unconfirmed", "body": "Unconfirmed suspicious activity sits between general worry and a real incident — worth taking seriously without overstating it.", "points": ["Ask what the suspicious activity actually looked like", "Suggest a quick review to confirm whether anything got through"], "next": "Investigate further — offer a light security review to clarify what really happened."}, "result_hot_ownership": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Clear Ownership", "body": "Ad hoc network ownership is a control gap and a business risk in its own right — easy to build urgency around accountability.", "points": ["Ask what happens today if something breaks — who do they actually call?", "Position a single point of ownership model"], "next": "Qualified on the control gap — propose managed ownership, not just kit."}, "result_warm_ownership": {"result": true, "level": "developing", "title": "Emerging Opportunity — Existing Provider", "body": "Someone already owns this — a displacement play rather than a greenfield sale.", "points": ["Ask what's good and bad about the current provider", "Find the renewal date"], "next": "Log the renewal date, nurture until contract end, and watch for coverage gaps."}, "result_mid_ownership": {"result": true, "level": "developing", "title": "Nominal Ownership, Under‑Resourced", "body": "Ownership exists on paper, but if the person is stretched thin, response times and follow‑through are likely suffering in practice.", "points": ["Ask how much time that person actually has for network management", "Position managed ownership as relieving pressure, not replacing them"], "next": "Nurture — position as capacity relief for an already‑stretched owner."}}, "situationFollowUp": {"q": "Before we get into specifics — how long has the network been set up this way, and has anything changed recently, like new starters, a new site, or more devices?", "options": [{"label": "It's been the same for years, nothing's really changed", "note": "Setup has been static for years — no recent trigger event."}, {"label": "We've grown or changed things recently — new starters, a new site, more devices", "note": "Recent growth or change — a natural moment to revisit the network setup."}]}, "implicationFollowUp": {"q": "Beyond what you've already mentioned, does this affect anything else — customers noticing, compliance requirements, or extra work for your team?", "options": [{"label": "Yes, it spills into other things too", "note": "The impact isn't contained — it spills into other areas of the business too."}, {"label": "No, it's really just contained to what I've said", "note": "The impact stays contained to what's already been discussed."}]}}];
